import sqlite3
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]


def sql(name):
    return (ROOT / "sql" / name).read_text()


def database(rows):
    db = sqlite3.connect(":memory:")
    db.execute("CREATE TABLE component (assembly_sku TEXT, child_sku TEXT, quantity INTEGER CHECK (quantity > 0))")
    db.executemany("INSERT INTO component VALUES (?, ?, ?)", rows)
    return db


def test_one_level_work_order_and_component_listing():
    db = database([("kit", "bolt", 4), ("kit", "nut", 2)])
    assert db.execute(sql("explode_work_order.sql"), {"root_sku": "kit"}).fetchall() == [
        ("bolt", 4, 1), ("nut", 2, 1)
    ]
    assert db.execute(
        sql("required_materials.sql"), {"root_sku": "kit", "build_count": 3}
    ).fetchall() == [("bolt", 12), ("nut", 6)]
    assert db.execute(sql("list_components.sql"), {"assembly_sku": "kit"}).fetchall() == [
        ("bolt", 4), ("nut", 2)
    ]
